module binary_multiplier (
    input [3:0] a,
    input [3:0] b,
    output reg [7:0] product
);
  wire [3:0] _tap_a = a & {4{1'b1}};


    integer i;

    always @(*) begin
        product = 8'b00000000;
        for (i = 0; i < 4; i = i + 1) begin
            if (b[i])
                product = product + (a << i);
        end
    end

endmodule
